     5→//! Curry command - paddock update operation for Heat context
     6→//!
     7→//! Supports getter mode (display paddock) and setter mode (update with chalk entry).
     8→//! Setter mode requires a verb flag (--refine, --level, --muck) to indicate update type.
     9→
    10→use std::path::PathBuf;
    11→use crate::jjrf_favor::{jjrf_Firemark as Firemark};
    12→use crate::jjrg_gallops::{jjrg_Gallops as Gallops};
    13→
    14→/// Curry verb for paddock update mode
    15→#[derive(Debug, Clone, Copy, PartialEq, Eq)]
    16→pub enum jjrcu_CurryVerb {
    17→    Refine,
    18→    Level,
    19→    Muck,
    20→}
    21→
    22→impl jjrcu_CurryVerb {
    23→    pub fn as_str(&self) -> &'static str {
    24→        match self {
    25→            jjrcu_CurryVerb::Refine => "refine",
    26→            jjrcu_CurryVerb::Level => "level",
    27→            jjrcu_CurryVerb::Muck => "muck",
    28→        }
    29→    }
    30→}
    31→
    32→/// Arguments for jjx_curry command
    33→#[derive(clap::Args, Debug)]
    34→pub struct jjrcu_CurryArgs {
    35→    /// Path to the Gallops JSON file
    36→    #[arg(long, short = 'f', default_value = ".claude/jjm/jjg_gallops.json")]
    37→    pub file: PathBuf,
    38→
    39→    /// Target Heat identity (Firemark)
    40→    pub firemark: String,
    41→
    42→    /// Verb for setter mode (required if stdin present)
    43→    #[arg(long)]
    44→    pub refine: bool,
    45→
    46→    #[arg(long)]
    47→    pub level: bool,
    48→
    49→    #[arg(long)]
    50→    pub muck: bool,
    51→
    52→    /// Optional note for chalk entry
    53→    #[arg(long)]
    54→    pub note: Option<String>,
    55→}
    56→
    57→/// Handler for jjx_curry command
    58→pub fn jjrcu_run_curry(args: jjrcu_CurryArgs) -> i32 {
    59→    use crate::jjro_ops::jjrg_curry;
    60→    use crate::jjrg_gallops::jjrg_read_stdin_optional;
    61→
    62→    // Parse firemark
    63→    let firemark = match Firemark::jjrf_parse(&args.firemark) {
    64→        Ok(fm) => fm,
    65→        Err(e) => {
    66→            eprintln!("jjx_curry: error: {}", e);
    67→            return 1;
    68→        }
    69→    };
    70→
    71→    // Check stdin
    72→    let stdin_content = match jjrg_read_stdin_optional() {
    73→        Ok(opt) => opt,
    74→        Err(e) => {
    75→            eprintln!("jjx_curry: error: {}", e);
    76→            return 1;
    77→        }
    78→    };
    79→
    80→    match stdin_content {
    81→        None => {
    82→            // Getter mode: display paddock content
    83→            let gallops = match Gallops::jjrg_load(&args.file) {
    84→                Ok(g) => g,
    85→                Err(e) => {
    86→                    eprintln!("jjx_curry: error loading Gallops: {}", e);
    87→                    return 1;
    88→                }
    89→            };
    90→
    91→            let firemark_key = firemark.jjrf_display();
    92→            let heat = match gallops.heats.get(&firemark_key) {
    93→                Some(h) => h,
    94→                None => {
    95→                    eprintln!("jjx_curry: error: Heat '{}' not found", firemark_key);
    96→                    return 1;
    97→                }
    98→            };
    99→
   100→            let paddock_path = std::path::Path::new(&heat.paddock_file);
   101→            let content = match std::fs::read_to_string(paddock_path) {
   102→                Ok(c) => c,
   103→                Err(e) => {
   104→                    eprintln!("jjx_curry: error reading paddock: {}", e);
   105→                    return 1;
   106→                }
   107→            };
   108→
   109→            print!("{}", content);
   110→            0
   111→        }
   112→        Some(new_content) => {
   113→            // Setter mode: require verb
   114→            let verb_count = [args.refine, args.level, args.muck]
   115→                .iter()
   116→                .filter(|&&x| x)
   117→                .count();
   118→
   119→            if verb_count == 0 {
   120→                eprintln!("jjx_curry: error: setter mode requires exactly one verb flag (--refine, --level, or --muck)");
   121→                return 1;
   122→            }
   123→            if verb_count > 1 {
   124→                eprintln!("jjx_curry: error: only one verb flag allowed");
   125→                return 1;
   126→            }
   127→
   128→            let verb = if args.refine {
   129→                jjrcu_CurryVerb::Refine
   130→            } else if args.level {
   131→                jjrcu_CurryVerb::Level
   132→            } else {
   133→                jjrcu_CurryVerb::Muck
   134→            };
   135→
   136→            // Call operation (curry acquires its own lock)
   137→            match jjrg_curry(&args.file, &firemark, &new_content, verb.as_str(), args.note.as_deref()) {
   138→                Ok(()) => {
   139→                    eprintln!("jjx_curry: paddock updated");
   140→                    0
   141→                }
   142→                Err(e) => {
   143→                    eprintln!("jjx_curry: error: {}", e);
   144→                    1
   145→                }
   146→            }
   147→        }
   148→    }
   149→}
