    10→
    11→#[test]
    12→fn jjtg_pace_state_serialization() {
    13→    let state = jjrg_PaceState::Rough;
    14→    let json = serde_json::to_string(&state).unwrap();
    15→    assert_eq!(json, "\"rough\"");
    16→}
    17→
    18→// Helper to create a minimal valid Gallops structure
    19→fn make_valid_gallops() -> jjrg_Gallops {
    20→    jjrg_Gallops {
    21→        next_heat_seed: "AB".to_string(),
    22→        heats: IndexMap::new(),
    23→    }
    24→}
    25→
    26→// Helper to create a valid Tack (uses JJRG_UNKNOWN_COMMIT for consistent commit format)
    27→fn make_valid_tack(state: jjrg_PaceState, silks: &str, direction: Option<String>) -> jjrg_Tack {
    28→    jjrg_Tack {
    29→        ts: "260101-1200".to_string(),
    30→        state,
    31→        text: "Test tack text".to_string(),
    32→        silks: silks.to_string(),
    33→        commit: JJRG_UNKNOWN_COMMIT.to_string(),
    34→        direction,
    35→    }
    36→}
    37→
    38→// Helper to create a valid Pace
    39→fn make_valid_pace(heat_id: &str, silks: &str) -> (String, jjrg_Pace) {
    40→    let pace_key = format!("₢{}AAA", heat_id);
    41→    let pace = jjrg_Pace {
    42→        tacks: vec![make_valid_tack(jjrg_PaceState::Rough, silks, None)],
    43→    };
    44→    (pace_key, pace)
    45→}
    46→
    47→// Helper to create a valid Heat
    48→fn make_valid_heat(heat_id: &str, silks: &str) -> (String, jjrg_Heat) {
    49→    let heat_key = format!("₣{}", heat_id);
    50→    let (pace_key, pace) = make_valid_pace(heat_id, "test-pace");
    51→    let mut paces = BTreeMap::new();
    52→    paces.insert(pace_key.clone(), pace);
    53→
    54→    let heat = jjrg_Heat {
    55→        silks: silks.to_string(),
    56→        creation_time: "260101".to_string(),
    57→        status: jjrg_HeatStatus::Racing,
    58→        order: vec![pace_key],
    59→        next_pace_seed: "AAB".to_string(),
    60→        paddock_file: ".claude/jjm/jjp_AB.md".to_string(),
    61→        paces,
    62→    };
    63→    (heat_key, heat)
    64→}
