     5→//! Gallops write operations
     6→//!
     7→//! All mutation operations on Gallops: nominate, slate, rail, tally, draft, retire, furlough.
     8→
     9→use std::collections::{BTreeMap, HashSet};
    10→use std::fs;
    11→use std::path::Path;
    12→use crate::jjrf_favor::{jjrf_Firemark as Firemark, jjrf_Coronet as Coronet, JJRF_FIREMARK_PREFIX as FIREMARK_PREFIX, JJRF_CORONET_PREFIX as CORONET_PREFIX};
    13→use crate::jjrs_steeplechase::jjrs_SteeplechaseEntry as SteeplechaseEntry;
    14→use crate::jjrt_types::*;
    15→use crate::jjru_util::{zjjrg_increment_seed, jjrg_make_tack};
    16→use crate::jjrv_validate::{zjjrg_is_kebab_case, zjjrg_is_yymmdd};
    17→
    18→/// Nominate a new Heat
    19→///
    20→/// Creates a new Heat with empty Pace structure and creates the paddock file.
    21→pub fn jjrg_nominate(gallops: &mut jjrg_Gallops, args: jjrg_NominateArgs, base_path: &Path) -> Result<jjrg_NominateResult, String> {
    22→    // Validate silks is kebab-case
    23→    if !zjjrg_is_kebab_case(&args.silks) {
    24→        return Err(format!("silks must be kebab-case, got '{}'", args.silks));
    25→    }
    26→
    27→    // Validate created is YYMMDD
    28→    if !zjjrg_is_yymmdd(&args.created) {
    29→        return Err(format!("created must be YYMMDD format, got '{}'", args.created));
    30→    }
    31→
    32→    // Allocate Firemark from next_heat_seed
    33→    let firemark_str = format!("{}{}", FIREMARK_PREFIX, gallops.next_heat_seed);
    34→    let heat_id = gallops.next_heat_seed.clone();
    35→
    36→    // Compute paddock path
    37→    let paddock_file = format!(".claude/jjm/jjp_{}.md", heat_id);
    38→
    39→    // Create paddock file with template
    40→    let paddock_path = base_path.join(&paddock_file);
    41→    if let Some(parent) = paddock_path.parent() {
    42→        fs::create_dir_all(parent)
    43→            .map_err(|e| format!("Failed to create paddock directory: {}", e))?;
    44→    }
    45→
    46→    let paddock_content = format!(
    47→        "# Paddock: {}\n\n## Context\n\n(Describe the initiative's background and goals)\n\n## References\n\n(List relevant files, docs, or prior work)\n",
    48→        args.silks
    49→    );
    50→
    51→    fs::write(&paddock_path, paddock_content)
    52→        .map_err(|e| format!("Failed to write paddock file: {}", e))?;
    53→
    54→    // Create new Heat
    55→    let heat = jjrg_Heat {
    56→        silks: args.silks,
    57→        creation_time: args.created,
    58→        status: jjrg_HeatStatus::Stabled,
    59→        order: Vec::new(),
    60→        next_pace_seed: "AAA".to_string(),
    61→        paddock_file,
    62→        paces: BTreeMap::new(),
    63→    };
    64→
    65→    // Insert Heat
    66→    gallops.heats.insert(firemark_str.clone(), heat);
    67→
    68→    // Increment next_heat_seed
    69→    gallops.next_heat_seed = zjjrg_increment_seed(&gallops.next_heat_seed);
    70→
    71→    Ok(jjrg_NominateResult { firemark: firemark_str })
    72→}
    73→
    74→/// Slate a new Pace
    75→///
    76→/// Adds a new Pace to a Heat with an initial Tack in rough state.
    77→/// Positioning: use before/after/first to insert at specific location.
    78→pub fn jjrg_slate(gallops: &mut jjrg_Gallops, args: jjrg_SlateArgs) -> Result<jjrg_SlateResult, String> {
    79→    // Validate silks is kebab-case
    80→    if !zjjrg_is_kebab_case(&args.silks) {
    81→        return Err(format!("silks must be kebab-case, got '{}'", args.silks));
    82→    }
    83→
    84→    // Validate text is non-empty
    85→    if args.text.is_empty() {
    86→        return Err("text must not be empty".to_string());
    87→    }
    88→
    89→    // Validate positioning mutual exclusivity
    90→    let position_count = [args.before.is_some(), args.after.is_some(), args.first]
    91→        .iter()
    92→        .filter(|&&x| x)
    93→        .count();
    94→    if position_count > 1 {
    95→        return Err("Only one of --before, --after, or --first may be specified".to_string());
    96→    }
    97→
    98→    // Parse and normalize firemark
    99→    let firemark = Firemark::jjrf_parse(&args.firemark)
   100→        .map_err(|e| format!("Invalid firemark: {}", e))?;
   101→    let firemark_key = firemark.jjrf_display();
   102→
   103→    // Verify Heat exists
   104→    let heat = gallops.heats.get_mut(&firemark_key)
   105→        .ok_or_else(|| format!("Heat '{}' not found", firemark_key))?;
   106→
   107→    // If --before or --after specified, validate target coronet exists
   108→    let insert_position = if let Some(ref before_str) = args.before {
   109→        let target = Coronet::jjrf_parse(before_str)
   110→            .map_err(|e| format!("Invalid --before coronet: {}", e))?;
   111→        let target_key = target.jjrf_display();
   112→        let pos = heat.order.iter().position(|c| c == &target_key)
   113→            .ok_or_else(|| format!("Target coronet '{}' not found in heat", target_key))?;
   114→        Some(pos) // Insert before this position
   115→    } else if let Some(ref after_str) = args.after {
   116→        let target = Coronet::jjrf_parse(after_str)
   117→            .map_err(|e| format!("Invalid --after coronet: {}", e))?;
   118→        let target_key = target.jjrf_display();
   119→        let pos = heat.order.iter().position(|c| c == &target_key)
   120→            .ok_or_else(|| format!("Target coronet '{}' not found in heat", target_key))?;
   121→        Some(pos + 1) // Insert after this position
   122→    } else if args.first {
   123→        Some(0) // Insert at beginning
   124→    } else {
   125→        None // Append to end (default)
   126→    };
   127→
   128→    // Construct Coronet
   129→    let coronet_str = format!("{}{}{}", CORONET_PREFIX, firemark.jjrf_as_str(), heat.next_pace_seed);
   130→
   131→    // Create initial Tack and Pace
   132→    let tack = jjrg_make_tack(
   133→        jjrg_PaceState::Rough,
   134→        args.text,
   135→        args.silks,
   136→        None,
   137→    );
   138→    let pace = jjrg_Pace {
   139→        tacks: vec![tack],
   140→    };
   141→
   142→    // Insert into order at determined position
   143→    match insert_position {
   144→        Some(pos) => heat.order.insert(pos, coronet_str.clone()),
   145→        None => heat.order.push(coronet_str.clone()),
   146→    }
   147→    heat.paces.insert(coronet_str.clone(), pace);
   148→
   149→    // Increment next_pace_seed
   150→    heat.next_pace_seed = zjjrg_increment_seed(&heat.next_pace_seed);
   151→
   152→    Ok(jjrg_SlateResult { coronet: coronet_str })
   153→}
   154→
   155→/// Rail - reorder Paces within a Heat
   156→///
   157→/// Supports two modes:
   158→/// - Order mode: replace entire sequence with provided order array
   159→/// - Move mode: relocate a single pace using positioning flags
   160→pub fn jjrg_rail(gallops: &mut jjrg_Gallops, args: jjrg_RailArgs) -> Result<Vec<String>, String> {
   161→    // Parse and normalize firemark
   162→    let firemark = Firemark::jjrf_parse(&args.firemark)
   163→        .map_err(|e| format!("Invalid firemark: {}", e))?;
   164→    let firemark_key = firemark.jjrf_display();
   165→
   166→    // Verify Heat exists
   167→    let heat = gallops.heats.get_mut(&firemark_key)
   168→        .ok_or_else(|| format!("Heat '{}' not found", firemark_key))?;
   169→
   170→    // Mode detection: if move_coronet present, use move mode
   171→    if let Some(ref move_str) = args.move_coronet {
   172→        // Move mode validation
   173→        if !args.order.is_empty() {
   174→            return Err("Cannot combine --move with positional coronets".to_string());
   175→        }
   176→
   177→        // Parse and normalize move coronet
   178→        let move_coronet = Coronet::jjrf_parse(move_str)
   179→            .map_err(|e| format!("Invalid --move coronet: {}", e))?;
   180→        let move_key = move_coronet.jjrf_display();
   181→
   182→        // Validate move coronet exists in heat
   183→        if !heat.paces.contains_key(&move_key) {
   184→            return Err(format!("Pace {} not found in heat {}", move_key, firemark_key));
   185→        }
   186→
   187→        // Count positioning flags
   188→        let position_count = [
   189→            args.before.is_some(),
   190→            args.after.is_some(),
   191→            args.first,
   192→            args.last,
   193→        ].iter().filter(|&&x| x).count();
   194→
   195→        if position_count == 0 {
   196→            return Err("Move mode requires exactly one positioning flag".to_string());
   197→        }
   198→        if position_count > 1 {
   199→            let mut flags = Vec::new();
   200→            if args.before.is_some() { flags.push("--before"); }
   201→            if args.after.is_some() { flags.push("--after"); }
   202→            if args.first { flags.push("--first"); }
   203→            if args.last { flags.push("--last"); }
   204→            return Err(format!("Conflicting positioning flags: {}", flags.join(", ")));
   205→        }
   206→
   207→        // Determine target position and validate
   208→        let current_pos = heat.order.iter().position(|c| c == &move_key)
   209→            .ok_or_else(|| format!("Pace {} not in order array", move_key))?;
   210→
   211→        let new_pos = if args.first {
   212→            // Find first actionable pace (rough or bridled)
   213→            // If none found, use end of array (nothing actionable to precede)
   214→            let first_actionable_idx = heat.order.iter().position(|coronet| {
   215→                if let Some(pace) = heat.paces.get(coronet) {
   216→                    if let Some(tack) = pace.tacks.first() {
   217→                        matches!(tack.state, jjrg_PaceState::Rough | jjrg_PaceState::Bridled)
   218→                    } else {
   219→                        false
   220→                    }
   221→                } else {
   222→                    false
   223→                }
   224→            });
   225→            // Use len() as fallback so adjustment logic works correctly for "end" position
   226→            let target_idx = first_actionable_idx.unwrap_or(heat.order.len());
   227→            // If moving from before target, the target shifts down after removal
   228→            if current_pos < target_idx {
   229→                target_idx - 1
   230→            } else {
   231→                target_idx
   232→            }
   233→        } else if args.last {
   234→            heat.order.len() - 1
   235→        } else if let Some(ref before_str) = args.before {
   236→            let target = Coronet::jjrf_parse(before_str)
   237→                .map_err(|e| format!("Invalid --before coronet: {}", e))?;
   238→            let target_key = target.jjrf_display();
   239→
   240→            if target_key == move_key {
   241→                return Err("Cannot position pace relative to itself".to_string());
   242→            }
   243→
   244→            let target_pos = heat.order.iter().position(|c| c == &target_key)
   245→                .ok_or_else(|| format!("Target pace {} not found in heat {}", target_key, firemark_key))?;
   246→
   247→            // If moving from before target, the target shifts down after removal
   248→            if current_pos < target_pos {
   249→                target_pos - 1
   250→            } else {
   251→                target_pos
   252→            }
   253→        } else if let Some(ref after_str) = args.after {
   254→            let target = Coronet::jjrf_parse(after_str)
   255→                .map_err(|e| format!("Invalid --after coronet: {}", e))?;
   256→            let target_key = target.jjrf_display();
   257→
   258→            if target_key == move_key {
   259→                return Err("Cannot position pace relative to itself".to_string());
   260→            }
   261→
   262→            let target_pos = heat.order.iter().position(|c| c == &target_key)
   263→                .ok_or_else(|| format!("Target pace {} not found in heat {}", target_key, firemark_key))?;
   264→
   265→            // If moving from before target, the target shifts down after removal
   266→            if current_pos < target_pos {
   267→                target_pos // After removal, target is at target_pos-1, we want target_pos-1+1 = target_pos
   268→            } else {
   269→                target_pos + 1
   270→            }
   271→        } else {
   272→            unreachable!()
   273→        };
   274→
   275→        // Remove from current position and insert at new position
   276→        heat.order.remove(current_pos);
   277→        heat.order.insert(new_pos, move_key);
   278→
   279→    } else {
   280→        // Order mode: replace entire sequence
   281→
   282→        // Normalize the input order (add prefix if missing)
   283→        let normalized_order: Result<Vec<String>, String> = args.order.iter()
   284→            .map(|c| {
   285→                let coronet = Coronet::jjrf_parse(c)
   286→                    .map_err(|e| format!("Invalid coronet '{}': {}", c, e))?;
   287→                Ok(coronet.jjrf_display())
   288→            })
   289→            .collect();
   290→        let new_order = normalized_order?;
   291→
   292→        // Validate count matches
   293→        if new_order.len() != heat.order.len() {
   294→            return Err(format!(
   295→                "Order count mismatch: got {}, expected {}",
   296→                new_order.len(),
   297→                heat.order.len()
   298→            ));
   299→        }
   300→
   301→        // Validate no duplicates
   302→        let new_set: HashSet<&String> = new_order.iter().collect();
   303→        if new_set.len() != new_order.len() {
   304→            return Err("Order contains duplicate Coronets".to_string());
   305→        }
   306→
   307→        // Validate all Coronets exist in paces
   308→        for coronet in &new_order {
   309→            if !heat.paces.contains_key(coronet) {
   310→                return Err(format!("Coronet '{}' not found in Heat's paces", coronet));
   311→            }
   312→        }
   313→
   314→        // Validate all Coronets embed correct parent Firemark
   315→        for coronet in &new_order {
   316→            let c = Coronet::jjrf_parse(coronet).unwrap();
   317→            if c.jjrf_parent_firemark().jjrf_display() != firemark_key {
   318→                return Err(format!(
   319→                    "Coronet '{}' does not embed parent Heat '{}'",
   320→                    coronet, firemark_key
   321→                ));
   322→            }
   323→        }
   324→
   325→        // Replace order
   326→        heat.order = new_order;
   327→    }
   328→
   329→    // Return the new order
   330→    Ok(heat.order.clone())
   331→}
