   730→/// Curry - update Heat paddock with chalk entry
   731→///
   732→/// Writes new paddock content and creates a chalk commit recording the change.
   733→/// Verb indicates the type of update: refine (manual), level (from another heat), muck (reduction).
   734→pub fn jjrg_curry(
   735→    gallops_path: &std::path::Path,
   736→    firemark: &Firemark,
   737→    new_content: &str,
   738→    verb: &str,
   739→    note: Option<&str>,
   740→) -> Result<(), String> {
   741→    use std::fs;
   742→
   743→    // Load gallops
   744→    let gallops = jjrg_Gallops::jjrg_load(gallops_path)
   745→        .map_err(|e| format!("Failed to load Gallops: {}", e))?;
   746→
   747→    // Verify heat exists
   748→    let firemark_key = firemark.jjrf_display();
   749→    let heat = gallops.heats.get(&firemark_key)
   750→        .ok_or_else(|| format!("Heat '{}' not found", firemark_key))?;
   751→
   752→    // Write new paddock content
   753→    let paddock_path = std::path::Path::new(&heat.paddock_file);
   754→    fs::write(paddock_path, new_content)
   755→        .map_err(|e| format!("Failed to write paddock file: {}", e))?;
   756→
   757→    // Build chalk message
   758→    let description = if let Some(n) = note {
   759→        format!("paddock curried ({}): {}", verb, n)
   760→    } else {
   761→        format!("paddock curried ({})", verb)
   762→    };
   763→
   764→    // Create chalk commit using vvc
   765→    use crate::jjrn_notch::jjrn_format_heat_discussion;
   766→    let message = jjrn_format_heat_discussion(firemark, &description);
   767→
   768→    let commit_args = vvc::vvcm_CommitArgs {
   769→        files: vec![paddock_path.to_string_lossy().to_string()],
   770→        message,
   771→        size_limit: vvc::VVCG_SIZE_LIMIT,
   772→        warn_limit: vvc::VVCG_WARN_LIMIT,
   773→    };
   774→
   775→    // Acquire lock for commit
   776→    let lock = vvc::vvcc_CommitLock::vvcc_acquire()
   777→        .map_err(|e| format!("Failed to acquire commit lock: {}", e))?;
   778→
   779→    match vvc::machine_commit(&lock, &commit_args) {
   780→        Ok(hash) => {
   781→            eprintln!("jjx_curry: committed {}", &hash[..8]);
   782→            Ok(())
   783→        }
   784→        Err(e) => Err(format!("Commit failed: {}", e)),
   785→    }
   786→    // lock released here
   787→}
